  `land_area` decimal(10,2) DEFAULT NULL COMMENT '鍗犲湴闈㈢Н(骞虫柟绫?',
  `building_area` decimal(10,2) DEFAULT NULL COMMENT '寤虹瓚闈㈢Н(骞虫柟绫?',
